public class MassApprovalExecutor implements Runnable {
	private APIQuery q;
    private RagicBundle bundle;
    private User user;
    private String userPassword;
    private String action;
    private String comment;
    private Log logger = Log.createStandardLog().setLevel(Log.DEBUG);
    public static final int MAX_APPROVAL_NUM = 1000;
    private List<String>errorMessages;
    private  Map<String,Integer> errorTypeCount;

    
    public MassApprovalExecutor(APIQuery q, RagicBundle bundle, User user, String action, String comment, String userPassword) {
        this.q = q;
        this.bundle = bundle;
        this.user = user;
        this.userPassword = null;
        this.action = action;
        this.comment = comment;
        this.userPassword = userPassword;
        this.errorMessages=new ArrayList<String>();
        this.errorTypeCount= new HashMap<>();
    }
    public List<String> getErrorMessages() {

        for(Map.Entry<String,Integer> i:errorTypeCount.entrySet()){
            String errorType=i.getKey();
            String text= bundle.getString(("approvalResponse_"+errorType),new Object[]{i.getValue()});
            errorMessages.add(0,text);
        }

        return errorMessages;
    }


    private void recordError(ApprovalResponse approvalResponse ,String type){

        String titleName=Encoder.uneJsString(Encoder.uneJsString(approvalResponse.getTitleName()));
        if(type.equals("wfNull")){
            if(approvalResponse.getErrorType().equals("checkEmpty")){
                List<String> errorMessage = approvalResponse.getMessages();
                if(errorMessage!=null||errorMessage.size()>0){
                    for(String i:errorMessage){
                        errorMessages.add(titleName+"   "+Encoder.uneJsString(Encoder.uneJsString(i)));
                    }
                }
            }else if(approvalResponse.getErrorType().equals("emptyAPIEntry")){
                if(this.errorTypeCount.containsKey("emptyAPIEntry")){
                    errorTypeCount.put("emptyAPIEntry", errorTypeCount.get("emptyAPIEntry")+1);
                }else{
                    errorTypeCount.put("emptyAPIEntry", 1);
                }

            }else if(approvalResponse.getErrorType().equals("emptyWorkflowID")){

                if(this.errorTypeCount.containsKey("emptyWorkflowID")){
                    errorTypeCount.put("emptyWorkflowID", errorTypeCount.get("emptyWorkflowID")+1);
                }else{
                    errorTypeCount.put("emptyWorkflowID", 1);
                }
            }
        }else{
            if(type.equals("noNextStep")){
                if(this.errorTypeCount.containsKey("noNextStep")){
                    errorTypeCount.put("noNextStep", errorTypeCount.get("noNextStep")+1);
                }else{
                    errorTypeCount.put("noNextStep", 1);
                }
            }
            else if(type.equals("notSigner")) {
                if (this.errorTypeCount.containsKey("notSigner")) {
                    errorTypeCount.put("notSigner", errorTypeCount.get("notSigner") + 1);
                } else {
                    errorTypeCount.put("notSigner", 1);
                }
            } else if(type.equals("actionIncorrect")) {
                if (this.errorTypeCount.containsKey("actionIncorrect")) {
                    errorTypeCount.put("actionIncorrect", errorTypeCount.get("actionIncorrect") + 1);
                } else {
                    errorTypeCount.put("actionIncorrect", 1);
                }
            }
        }
    }

    public void run() {
        System.out.println("------------------");
        for(Map.Entry<String,Integer> i:errorTypeCount.entrySet()){
            System.out.println("json:"+i.getKey()+","+i.getValue());
        }
        NUIForm form = q.getForm();
        
        // Register Long term task
        LongTermTask ltt = ThreadManager.getInstance().addTask(Thread.currentThread(),form.getApname(), "Mass Approval: " + form.getRealname() + " (" + form.getUrl() + ")");
        
        // Register running service
        MassApprovalRunningService rs = new MassApprovalRunningService(form.getUrl());
        RunningServiceRegister.getInstance().addService(form.getApname(), rs);
        
        // Do actual update
        String resultMessage = bundle.getString("massApproval_execution_end");
        boolean ifFailed = false;
        int count_succ = 0;
        int count_failed = 0;
        try {
            // Check if allow rejection
        	if("reject".equals(this.action) && !form.isAllowedApprovalRejection()) {
                throw new Exception(bundle.getString("massApproval_execution_failed_notAllowRejection"));
            }
            
            // Check if password needed
            if(form.isStrictApproval()) {
                if(userPassword == null || RemoteAccountManager.main_authenticateUser(user.getUserId(), userPassword, "PWD") == null) {
                	throw new Exception(bundle.getString("massApproval_execution_failed_wrongPassword"));
                }
            }
            
        	// Update system task progress
            SystemTaskProgress.setStatus(form.getApname(),Const.STP_APPROVAL, bundle.getString("massApproval_execution_start"), -1, SystemTaskProgress.Status.PROCESSING);
            
        	// Get records to be updated
            final Set<Integer> filteredRootNodeIds = new HashSet<>();
            APIFullIteration ite = new APIFullIteration(q) {
                public void entryCustomAction(APIEntry entry, int runningCount) {
                    filteredRootNodeIds.add(entry.getRootNodeId());
                }
            };
            ite.setPageSize(100);
            ite.iterate();

            if(filteredRootNodeIds.size() > MAX_APPROVAL_NUM) throw new RuntimeException(bundle.getString("massApproval_execution_failed_tooManyRecords", new Object[] {MAX_APPROVAL_NUM}));
            
            for(int rootNodeId: filteredRootNodeIds) {
                try {
                	MassApprovalException e = new MassApprovalException(form, rootNodeId);
                    WorkflowApprovalAgent approvalAgent = new WorkflowApprovalAgent(form, rootNodeId, user, bundle);
                    approvalAgent.setUserAuthenticated(true);

                    ApprovalResponse approvalResponse = new ApprovalResponse();
                    Workflow wf = approvalAgent.getCurrentWorkflowCheckError(approvalResponse);
                    String tableName=Encoder.uneJsString(Encoder.uneJsString(approvalResponse.getTableName()));
                    String titleName=Encoder.uneJsString(Encoder.uneJsString(approvalResponse.getTitleName()));
                    if(wf == null){
                        recordError(approvalResponse,"wfNull");
                        throw new Exception("Workflow not found.");
                    }

                    WorkflowStep nextStep = wf.getNextWorkStep().orElse(null);
                    if(nextStep == null){
                        recordError(approvalResponse,"noNextStep");
                        throw e.setMessage("WorkflowStep not found");
                    }
                    
                    String signResponse = null;
                    // Check signers
                    List<String> signers = nextStep.getEmails();
                    if(signers.contains(user.getUserId())) {
                    	if(action.equals("approve")) {
                    		signResponse = Workflow.ACCEPT;
                        } else if(action.equals("reject")) {
                        	signResponse = Workflow.REJECT;
                        }
                    } else {
                    	boolean ifDeputy = false;
                        BDBWorker worker = new BDBWorker(form.getApname());
                        try {
                        	for(String signer: signers) {
                        		ifDeputy = this.ifDeputy(signer, user.getUserId(), worker);
                                if(ifDeputy) break;
                            }
                        } finally {
                            worker.commit();
                        }
                        if(ifDeputy) {
                        	if(action.equals("approve")) {
                                signResponse = Workflow.ACCEPT_BY_DEPUTY;
                            } else if(action.equals("reject")) {
                                signResponse = Workflow.REJECT_BY_DEPUTY;
                            }
                        } else {
                            recordError(approvalResponse,"notSigner");
                        	throw e.setMessage("Not signer");
                        }
                    }
                    if(signResponse == null) throw e.setMessage("Wrong signResponse");

                    ApprovalSigningInfo signingInfo = new ApprovalSigningInfo();
                    signingInfo.setComment(comment);
                    signingInfo.setPwd(this.userPassword);
                    signingInfo.setContinuousSigning(true);
                    approvalResponse = new ApprovalResponse();
                    SignResult result = approvalAgent.signApproval(wf.getWfId(), signResponse, signingInfo, approvalResponse);

                    if(result != SignResult.SIGN_SUCCESS && result != SignResult.SIGN_PARTIAL_SUCCESS) throw e.setMessage("Sign approval failed: " + result.name());
                    
                    count_succ++;
                    SystemTaskProgress.setStatus(form.getApname(),Const.STP_APPROVAL, bundle.getString("massApproval_execution_count", new Object[] {count_succ}), -1, SystemTaskProgress.Status.PROCESSING);
                } catch(MassApprovalException e) {
                    logger.debug("Mass approval for " + e.getRecordUrl() + " failed: " + e.getMessage());
                    logger.debug(e);
                    count_failed++;
                } catch(Exception e_unknown) {
                    logger.debug(e_unknown);
                	count_failed++;
                }
            }
        } catch(Exception e) {
        	ifFailed = true;
            resultMessage = bundle.getString("massApproval_execution_failed", new Object[] {e.getMessage()});
        } finally {
            // Remove running service
            RunningServiceRegister.getInstance().removeService(form.getApname(), rs);
            
            // Remove long term task
            ThreadManager.getInstance().removeTask(ltt);
            
            // Update system task progress
            if(!ifFailed) resultMessage = bundle.getString("massApproval_execution_end", new Object[] {count_succ, count_failed});
            SystemTaskProgress.setStatus(form.getApname(),Const.STP_APPROVAL, resultMessage, -1, ifFailed? SystemTaskProgress.Status.ERROR: SystemTaskProgress.Status.DONE);
        }
    }
    
	private boolean ifDeputy(String signer, String userId, BDBWorker worker) {
	    int signerRootNodeId = -1;
	    
	    Account acc = Account.getInstance(worker.getApname());
	    Map<Integer, String> m_userRootNodeId_email = acc.getUserNodeIdToEmail();
	    for(Map.Entry<Integer, String> e: m_userRootNodeId_email.entrySet()) {
	        if(e.getValue().equals(signer)) {
	            signerRootNodeId = e.getKey();
	            break;
	        }
	    }
	    
	    if(signerRootNodeId < 0) return false;
	    
	    SDBNode node_deputy = worker.getLinkedNode(DConst.USER_USERID_EMAIL, signerRootNodeId, DConst.USER_DEPUTY);
        if(node_deputy == null || node_deputy.getValue() == null) return false;
        
        if(node_deputy.getValue().equals(userId)) return true;
	    
	    return false;
	}
}

private class MassApprovalException extends Exception {
    private String ap = null;
    private String path = null;
    private int sheetIndex = -1;
    private int rootNodeId = -1;
    private String errMsg = null;
    
    public MassApprovalException(NUIForm form, int rootNodeId) {
        this.ap = form.getApname();
        this.path = form.getPath();
        this.sheetIndex = Encoder.parseInt(form.getSheetIndex(), -1);
        this.rootNodeId = rootNodeId;
    }
    
    public MassApprovalException setMessage(String msg) {
        this.errMsg = msg;
        return this;
    }
    
    @Override
    public String getMessage() {
        return this.errMsg;
    }
    
    public String getRecordUrl() {
        return this.ap + this.path + "/" + this.sheetIndex + "/" + this.rootNodeId;
    }
}

